using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using verii_metivon_api.Core.Auth;using verii_metivon_api.Modules.Sales.Application.Parameters;
namespace verii_metivon_api.Modules.Sales.Api;[ApiController,Authorize,Route("api/parameters/sales-orders")]public sealed class SalesOrderParametersController(ISalesOrderParameterService service):ControllerBase{[HttpGet]public async Task<IActionResult>Get([FromQuery]long?branchId,[FromQuery]long?warehouseId,CancellationToken ct)=>Ok(ApiResponse<SalesOrderParametersDto>.Ok(await service.GetAsync(branchId,warehouseId,ct)));[HttpPut,Authorize(Roles="Admin")]public async Task<IActionResult>Save(SaveSalesOrderParametersRequest r,CancellationToken ct){try{return Ok(ApiResponse<SalesOrderParametersDto>.Ok(await service.SaveAsync(r,ct)));}catch(ArgumentException e){return BadRequest(ApiResponse<object>.Error(e.Message,400));}}}
